	router.POST(options.BaseURL+"/api/events", wrapper.ReceiveEvent, options.OperationMiddlewares["receiveEvent"]...)
	router.GET(options.BaseURL+"/api/groups", wrapper.ListGroups, options.OperationMiddlewares["listGroups"]...)
	router.DELETE(options.BaseURL+"/api/groups/:group_id", wrapper.DeleteGroup, options.OperationMiddlewares["deleteGroup"]...)
	router.PATCH(options.BaseURL+"/api/groups/:group_id", wrapper.RenameGroup, options.OperationMiddlewares["renameGroup"]...)
	router.GET(options.BaseURL+"/api/instances", wrapper.ListInstances, options.OperationMiddlewares["listInstances"]...)
	router.DELETE(options.BaseURL+"/api/instances/:instance_id", wrapper.DeleteInstance, options.OperationMiddlewares["deleteInstance"]...)
	router.GET(options.BaseURL+"/api/instances/:instance_id", wrapper.GetInstance, options.OperationMiddlewares["getInstance"]...)
